mapper.update:
UPDATE application_runtime_setting
   SET setting_group = #{settingGroup}, display_name = #{displayName},
       setting_value = #{settingValue}, fallback_value = #{fallbackValue}, value_type = #{valueType},
       secret = #{secret}, editable = #{editable}, active = #{active},
       description = #{description}, updated_by = #{updatedBy}
 WHERE setting_key = #{settingKey}

mapper.select:

SELECT id, setting_id, setting_key, version_no, change_type, actor_user_id,
       before_value, after_value, before_fallback, after_fallback, reason, created_at
  FROM application_runtime_setting_history

    AND setting_key = #{settingKey}

 ORDER BY id DESC
 LIMIT #{limit}
